sql:
SELECT AVG(co2) AS average_co2, MAX(temperature) AS max_temperature
FROM carbon_data
WHERE collection_date = '2023-05-01';

SELECT collection_date, temperature
FROM carbon_data
ORDER BY collection_date;

SELECT soc
FROM carbon_data
WHERE soil_type = 'Clay' AND collection_date = '2023-01-01';

SELECT COUNT(*) AS data_count
FROM carbon_data
WHERE soil_type = 'Clay';

